import xml.etree.ElementTree as ET
from io import BytesIO

def validate_xml(xml_data):
    try:
        # Parse the XML data
        root = ET.fromstring(xml_data)
        
        # Check if the root element is not None
        if root is None:
            return False, "Invalid XML"
        
        # Perform additional validation logic here (e.g., check for specific tags or attributes)
        # Example: Ensure there is at least one 'item' tag
        if len(root.findall('.//item')) == 0:
            return False, "No items found in the XML"
        
        return True, "XML is valid"

    except ET.ParseError as e:
        return False, f"XML parsing error: {e}"

